esqlQuery.esql:
FROM metrics-tomcat.otel-*
| WHERE java_lang_OperatingSystem_ProcessCpuLoad IS NOT NULL
| STATS avg_cpu = AVG(java_lang_OperatingSystem_ProcessCpuLoad)
  BY host.name
| EVAL cpu_pct = ROUND(avg_cpu * 100.0, 2)
// JVM process CPU threshold — sustained high CPU often correlates with
// GC pressure, thread contention, or compute-heavy request processing
// Adjust based on expected workload and available CPU cores
| WHERE cpu_pct > 90.0
| SORT cpu_pct DESC
